const a = [
  {"id":392,"text":"Which of the following can cause inhibition of action potential?","explanation":"**Influx of chloride ions (Cl-)** can indeed inhibit action potentials in neurons. Chloride ions are negatively charged, and their influx into a neuron can lead to membrane **hyperpolarization**, making it more difficult for the neuron to reach the threshold for firing an action potential.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 581.","responses":[{"text":"Influx of chloride","correct":true,"visible":false},{"text":"Influx of potassium","correct":false,"visible":false},{"text":"Influx of sodium","correct":false,"visible":false},{"text":"Influx of calcium","correct":false,"visible":false},{"text":"Influx of bicarbonate","correct":false,"visible":false}]},{"id":5236,"text":"Which of the following arteries gives rise to the nutrient artery of the fibula?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 761.","responses":[{"text":"Popliteal artery","correct":false,"visible":false},{"text":"Inferior medial genicular artery","correct":false,"visible":false},{"text":"Posterior tibial artery","correct":false,"visible":false},{"text":"Anterior tibial artery","correct":false,"visible":false},{"text":"Peroneal artery","correct":true,"visible":false}]},{"id":5242,"text":"Which of the following muscles pass through the greater sciatic foramen?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 568.","responses":[{"text":"Obturator externus","correct":false,"visible":false},{"text":"Obturator internus","correct":false,"visible":false},{"text":"Piriformis","correct":true,"visible":false},{"text":"Quadratus femoris","correct":false,"visible":false},{"text":"Superior and inferior gemelli","correct":false,"visible":false}]},{"id":5256,"text":"What are the contents of the femoral sheath from the lateral to the medial side?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 710.","responses":[{"text":"Femoral nerve, femoral artery, and the femoral vein","correct":false,"visible":false},{"text":"Femoral vein, femoral artery, and the lymphatic vessels","correct":false,"visible":false},{"text":"Femoral vein, femoral artery, and the femoral nerve","correct":false,"visible":false},{"text":"Femoral artery, femoral vein, and the lymphatic vessels","correct":true,"visible":false},{"text":"Femoral nerve, femoral artery, femoral vein, and the inguinal lymph nodes","correct":false,"visible":false}]},{"id":5265,"text":"Which of the following structures are present in the femoral canal?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 713.","responses":[{"text":"Femoral artery, vein, and the lymphatic vessels","correct":false,"visible":false},{"text":"Femoral artery","correct":false,"visible":false},{"text":"Lymphatic vessels and sometimes deep inguinal lymph nodes","correct":true,"visible":false},{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Femoral vein","correct":false,"visible":false}]},{"id":5277,"text":"The femoral sheath is formed by which of the following layers of fascia?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 713.","responses":[{"text":"The fascia lata and the membranous layer of the superficial fascia","correct":false,"visible":false},{"text":"The fascia iliaca and fascia transversalis","correct":true,"visible":false},{"text":"The processes vaginalis","correct":false,"visible":false},{"text":"The psoas fascia and the fatty layer of the superficial fascia","correct":false,"visible":false},{"text":"the pectineus fascia","correct":false,"visible":false}]},{"id":5352,"text":"Which of the following muscles attach to the lesser tubercle of the humerus?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 692.","responses":[{"text":"Infraspinatus","correct":false,"visible":false},{"text":"Subscapularis","correct":true,"visible":false},{"text":"Teres minor","correct":false,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false}]},{"id":5353,"text":"Which of the following is the longest muscle in the human body?","explanation":"The **longest muscle** in the human body is the **sartorius muscle**. It runs diagonally across the thigh, originating from the anterior superior iliac spine and inserting into the medial side of the tibia. The sartorius is involved in flexing, abducting, and laterally rotating the thigh at the hip joint, as well as flexing the knee.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 706.","responses":[{"text":"Iliacus","correct":false,"visible":false},{"text":"Psoas major","correct":false,"visible":false},{"text":"Vastus medialis","correct":false,"visible":false},{"text":"Sartorius","correct":true,"visible":false},{"text":"Pectineus","correct":false,"visible":false}]},{"id":5371,"text":"Which of the following muscle pairs is involved in the abduction of the upper limb after the first 90 degrees of movement?","explanation":null,"reference":"(1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 180. (2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 89.","responses":[{"text":"Deltoid and levator scapulae","correct":false,"visible":false},{"text":"Trapezius and serratus anterior","correct":true,"visible":false},{"text":"Deltoid and supraspinatus","correct":false,"visible":false},{"text":"Deltoid and trapezius","correct":false,"visible":false},{"text":"Trapezius and levator scapulae","correct":false,"visible":false}]},{"id":5447,"text":"Which of the following statements is correct regarding the route of the great saphenous vein?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 655.","responses":[{"text":"Posterior to the medial malleolus","correct":false,"visible":false},{"text":"Anterior to the medial condyle of the tibia and femur","correct":false,"visible":false},{"text":"Anterior to the medial malleolus","correct":true,"visible":false},{"text":"Passes up the lateral side of the leg","correct":false,"visible":false},{"text":"Joins the femoral vein superficial to the fascia lata","correct":false,"visible":false}]},{"id":5470,"text":"What is the most common site for the fracture of a clavicle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 153.","responses":[{"text":"Junction of lateral three fourth of a clavicle with medial one fourth","correct":false,"visible":false},{"text":"Junction of medial three fourth of a clavicle with lateral one fourth","correct":false,"visible":false},{"text":"Junction of medial two third of a clavicle with lateral one third","correct":true,"visible":false},{"text":"Junction of lateral two third of a clavicle with medial one third","correct":false,"visible":false},{"text":"The mid point of the clavicle","correct":false,"visible":false}]},{"id":5471,"text":"Which of the following types of cells do Howship's lacunae contain?","explanation":"**Howship's lacunae** contain **osteoclasts**. These are specialized cells responsible for the resorption of bone tissue. Howship's lacunae are small pits on the surface of bone where osteoclasts are active. The osteoclasts attach to the bone surface and create an isolated environment where they can break down the bone matrix, releasing calcium and other minerals back into the bloodstream.\r\n\r\n---\r\n\r\nChondrocytes are cells that produce and maintain cartilage tissue.\r\nOsteoprogenitor cells are precursor cells that can differentiate into osteoblasts.\r\nOsteoblasts are cells responsible for bone formation.\r\nOsteocytes refer to mature bone cells that maintain the bone matrix.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 143.","responses":[{"text":"Chondrocytes","correct":false,"visible":false},{"text":"Osteoprogenitor cells","correct":false,"visible":false},{"text":"Osteocytes","correct":false,"visible":false},{"text":"Osteoblasts","correct":false,"visible":false},{"text":"Osteoclasts","correct":true,"visible":false}]},{"id":5478,"text":"Cardiac muscle is derived from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 359.","responses":[{"text":"Somatic mesoderm","correct":false,"visible":false},{"text":"Splanchnic mesoderm","correct":true,"visible":false},{"text":"Paraxial mesoderm","correct":false,"visible":false},{"text":"Intermediate mesoderm","correct":false,"visible":false},{"text":"Lateral plate mesoderm","correct":false,"visible":false}]},{"id":5479,"text":"Which of the following is the reason behind the resilience and shock-absorbing nature of cartilage?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 129.","responses":[{"text":"Non-covalent bonding between glycosaminoglycans (GAGs) and proteins","correct":false,"visible":false},{"text":"Regenerative ability of chondrocytes","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Ossification of cartilage","correct":false,"visible":false},{"text":"Hydration of glycosaminoglycans (GAGs)","correct":true,"visible":false}]},{"id":5480,"text":"Which of the following fibers is the fastest nerve fiber?","explanation":null,"reference":"Costanzo LS. BRS: Physiology. 7th ed. Wolters Kluwer; 2019: 39.","responses":[{"text":"A-gamma fibers","correct":false,"visible":false},{"text":"A-delta fibers","correct":false,"visible":false},{"text":"A-beta fibers","correct":false,"visible":false},{"text":"A-alpha fibers","correct":true,"visible":false},{"text":"A-epsilon fibers","correct":false,"visible":false}]},{"id":5481,"text":"Which orientation is preferred for the X-ray of long bones?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Radiology.","responses":[{"text":"Posterior-anterior (PA) and lateral view","correct":false,"visible":false},{"text":"Anterior-posterior (AP) and lateral view","correct":true,"visible":false},{"text":"Anterior-posterior (AP) and oblique view","correct":false,"visible":false},{"text":"Posterior-anterior (PA) and oblique view","correct":false,"visible":false},{"text":"Anterior-posterior (AP) and medial view","correct":false,"visible":false}]},{"id":5482,"text":"Which of the following arteries enter the gluteal region by passing over the piriformis muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 734.","responses":[{"text":"Lateral circumflex femoral artery","correct":false,"visible":false},{"text":"Superior gluteal artery","correct":true,"visible":false},{"text":"Inferior gluteal artery","correct":false,"visible":false},{"text":"Femoral artery","correct":false,"visible":false},{"text":"Superior epigastric artery","correct":false,"visible":false}]},{"id":5483,"text":"Which of the following veins pass through the deltopectoral triangle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 688.","responses":[{"text":"Subclavian vein","correct":false,"visible":false},{"text":"Brachial vein","correct":false,"visible":false},{"text":"Cephalic vein","correct":true,"visible":false},{"text":"Basilic vein","correct":false,"visible":false},{"text":"Axillary vein","correct":false,"visible":false}]},{"id":5484,"text":"To which of the following structures does the flexor retinaculum attach medially?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 783.","responses":[{"text":"Tubercle of scaphoid and ridge of trapezium","correct":false,"visible":false},{"text":"Hook of hamate and pisiform","correct":true,"visible":false},{"text":"Pisiform and trapezoid","correct":false,"visible":false},{"text":"Tubercle of scaphoid and hook of hamate","correct":false,"visible":false},{"text":"Ridge of trapezium and hook of hamate","correct":false,"visible":false}]},{"id":5485,"text":"Which of the following veins combine to form the axillary vein?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 188.","responses":[{"text":"Basilic vein and brachial vein","correct":true,"visible":false},{"text":"Basilic vein and subclavian vein","correct":false,"visible":false},{"text":"Brachial vein and cephalic vein","correct":false,"visible":false},{"text":"Basilic vein and radial vein","correct":false,"visible":false},{"text":"Basilic vein and cephalic vein","correct":false,"visible":false}]},{"id":5488,"text":"Which of the following pair of joints is involved in the inversion and eversion of the foot?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 10.","responses":[{"text":"Talocrural and talocalcanial joint","correct":false,"visible":false},{"text":"Subtalar and talocrural joint","correct":false,"visible":false},{"text":"Subtalar and transverse tarsal joint","correct":true,"visible":false},{"text":"Talotibial and talocalcanial","correct":false,"visible":false},{"text":"Transverse tarsal and tibiotalar joint","correct":false,"visible":false}]},{"id":5489,"text":"Which of the following is the keystone of the medial longitudinal arch of the foot?","explanation":"The **talus head** is the keystone of the **medial longitudinal arch** of the foot. The medial longitudinal arch is composed of the calcaneus, talus, navicular, three cuneiforms, and three metatarsals. The talar head serves as the central point around which the arch is formed and provides crucial support to the structure of the foot. The tibialis anterior and posterior muscles, via their tendinous attachments, also help in supporting this arch.","reference":"Halliday NL, M C Harold, Won C Kyung. BRS: Gross Anatomy. 10th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2020: 228.","responses":[{"text":"Navicular bone","correct":false,"visible":false},{"text":"Calcaneal tubercle","correct":false,"visible":false},{"text":"Talus head","correct":true,"visible":false},{"text":"Medial cuneiform bone","correct":false,"visible":false},{"text":"Metatarsals","correct":false,"visible":false}]},{"id":5490,"text":"Which muscle divides the axillary artery into three parts?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 722.","responses":[{"text":"Pectoralis major","correct":false,"visible":false},{"text":"Pectoralis minor","correct":true,"visible":false},{"text":"Teres minor","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Coracobrachialis","correct":false,"visible":false}]},{"id":5500,"text":"How much additional potential difference is created when the sodium-potassium pump transfers three sodium ions outside the cell and two potassium ions inside the cell?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 67.","responses":[{"text":"-2 mV","correct":false,"visible":false},{"text":"-1 mV","correct":false,"visible":false},{"text":"-3 mV","correct":false,"visible":false},{"text":"-4 mV","correct":true,"visible":false},{"text":"-5 mV","correct":false,"visible":false}]},{"id":5515,"text":"What does a comminuted fracture mean?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1183.","responses":[{"text":"A fracture with splintered bones","correct":true,"visible":false},{"text":"A simple fracture","correct":false,"visible":false},{"text":"An open fracture","correct":false,"visible":false},{"text":"A fracture with unaligned bones","correct":false,"visible":false},{"text":"A closed fracture","correct":false,"visible":false}]},{"id":5517,"text":"Damage to which pair of nerves is responsible for loss of inversion of the foot?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 811.","responses":[{"text":"Deep peroneal and tibial nerve","correct":true,"visible":false},{"text":"Tibial and common peroneal nerve","correct":false,"visible":false},{"text":"Superficial peroneal and sural nerve","correct":false,"visible":false},{"text":"Superficial peroneal and tibial nerve","correct":false,"visible":false},{"text":"Superficial and deep peroneal nerve","correct":false,"visible":false}]},{"id":5533,"text":"Which cofactor is necessary for hydroxylation during collagen synthesis?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 47.","responses":[{"text":"Ascorbate","correct":true,"visible":false},{"text":"Calcitriol","correct":false,"visible":false},{"text":"Cholecalciferol","correct":false,"visible":false},{"text":"Retinol","correct":false,"visible":false},{"text":"Folate","correct":false,"visible":false}]},{"id":5534,"text":"Which long bone of the lower limb has the medial malleolus as its normal anatomical part?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 680.","responses":[{"text":"Fibula","correct":false,"visible":false},{"text":"Talus","correct":false,"visible":false},{"text":"Navicular bone","correct":false,"visible":false},{"text":"Femur","correct":false,"visible":false},{"text":"Tibia","correct":true,"visible":false}]},{"id":5538,"text":"Which muscle is most likely to be impaired when a person is unable to flex, abduct, and laterally rotate his thigh?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 704.","responses":[{"text":"Sartorius","correct":true,"visible":false},{"text":"Adductor longus","correct":false,"visible":false},{"text":"Obturator externus","correct":false,"visible":false},{"text":"Gluteus medius","correct":false,"visible":false},{"text":"Gracilis","correct":false,"visible":false}]},{"id":5546,"text":"Which of the following nerves will be damaged by the fracture of a neck of the humerus?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 693.","responses":[{"text":"Radial nerve","correct":false,"visible":false},{"text":"Axillary nerve","correct":true,"visible":false},{"text":"Musculocutaneous nerve","correct":false,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Median nerve","correct":false,"visible":false}]},{"id":5564,"text":"Which of the following pairs of nerves supply the lumbricals?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 799.","responses":[{"text":"Median and radial nerve","correct":false,"visible":false},{"text":"Median and musculocutaneous nerve","correct":false,"visible":false},{"text":"Radial and ulnar nerve","correct":false,"visible":false},{"text":"Median and ulnar nerve","correct":true,"visible":false},{"text":"Ulnar and musculocutaneous nerve","correct":false,"visible":false}]},{"id":5566,"text":"What is the action of the serratus anterior on the scapula?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 716.","responses":[{"text":"Depression","correct":false,"visible":false},{"text":"Protraction","correct":true,"visible":false},{"text":"Retraction","correct":false,"visible":false},{"text":"Downward rotation","correct":false,"visible":false},{"text":"Elevation","correct":false,"visible":false}]},{"id":5569,"text":"Which of the following muscles is responsible for the lateral rotation and flexion of the thigh at the hip joint?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 704, 723, 729.","responses":[{"text":"Gracilis","correct":false,"visible":false},{"text":"Sartorius","correct":true,"visible":false},{"text":"Adductor longus","correct":false,"visible":false},{"text":"Pectineus","correct":false,"visible":false},{"text":"Vastus lateralis","correct":false,"visible":false}]},{"id":5570,"text":"Which of the following is associated with Klumpke's palsy?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 200.","responses":[{"text":"Claw hand","correct":true,"visible":false},{"text":"Waitor's tip hand","correct":false,"visible":false},{"text":"Shoulder drop","correct":false,"visible":false},{"text":"Hand of benediction","correct":false,"visible":false},{"text":"Wrist drop","correct":false,"visible":false}]},{"id":5575,"text":"Which of the following muscles attaches to the nuchal ligament?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 91.","responses":[{"text":"Rhomboid major","correct":false,"visible":false},{"text":"Rhomboid minor","correct":true,"visible":false},{"text":"Latissimus dorsi","correct":false,"visible":false},{"text":"Levator scapulae","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false}]},{"id":5581,"text":"Which of the following is not one of the key principles of health education?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Health Promotion and Health Education, Sub-topic: Health Education.","responses":[{"text":"Change of behavior","correct":false,"visible":false},{"text":"Creating habits","correct":true,"visible":false},{"text":"Knowing customs","correct":false,"visible":false},{"text":"Learning by doing","correct":false,"visible":false},{"text":"Good relations","correct":false,"visible":false}]},{"id":5587,"text":"A 34-old man presents to the outpatient department with a complaint of inability to extend his leg at the knee joint. Which of the following nerves is most likely to be affected?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 705.","responses":[{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Tibial nerve","correct":false,"visible":false},{"text":"Peroneal nerve","correct":false,"visible":false},{"text":"Femoral nerve","correct":true,"visible":false},{"text":"Obturator nerve","correct":false,"visible":false}]},{"id":5595,"text":"In which of the following conditions does the high turnover osteoporosis occur?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1180.","responses":[{"text":"High progesterone","correct":false,"visible":false},{"text":"Low calcium and low vitamin D","correct":false,"visible":false},{"text":"High estrogen","correct":false,"visible":false},{"text":"Low progesterone","correct":false,"visible":false},{"text":"Low estrogen","correct":true,"visible":false}]},{"id":5614,"text":"If a child's elbow gets fractured and the fractured segment moves posteriorly then which of the following artery will get damaged?","explanation":null,"reference":"Vickash K, Amer A, Naeem A, Falak S. Brachial artery injury in a child following closed elbow dislocation: case report of a rare injury. Malaysian Orthopaedic Journal. Published November 1, 2016. Accessed September 15, 2022. http://morthoj.org/2016/v10n3/brachial-artery-injury.pdf","responses":[{"text":"Ulnar artery","correct":false,"visible":false},{"text":"Brachial artery","correct":true,"visible":false},{"text":"Cephalic artery","correct":false,"visible":false},{"text":"Axillary artery","correct":false,"visible":false},{"text":"Radial artery","correct":false,"visible":false}]},{"id":5615,"text":"Which of the following drugs is a cyclooxygenase-1 and cyclooxygenase-2 inhibitor?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 498.","responses":[{"text":"Paracetamol","correct":false,"visible":false},{"text":"Acetaminophen","correct":false,"visible":false},{"text":"Dipyrone","correct":false,"visible":false},{"text":"Aspirin","correct":true,"visible":false},{"text":"Antipyrine","correct":false,"visible":false}]},{"id":5617,"text":"Which neurotransmitter is involved in the conduction of superficial pain?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 616.","responses":[{"text":"Vasoactive intestinal peptide","correct":false,"visible":false},{"text":"Glutamate","correct":true,"visible":false},{"text":"Tryptophan","correct":false,"visible":false},{"text":"Serotonin","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false}]},{"id":5623,"text":"Extraembryonic mesoderm is present in between which of the following?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 52-53.","responses":[{"text":"Extraembryonic membrane and cytotrophoblast","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Extraembryonic membrane and syncitiotrophoblast","correct":false,"visible":false},{"text":"Exocoelomic membrane and cytotrophoblast","correct":true,"visible":false},{"text":"Syncytiotrophoblast and cytotrophoblast","correct":false,"visible":false}]},{"id":5625,"text":"Which of these is the largest protein in skeletal muscle fibers?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79.","responses":[{"text":"Titin","correct":true,"visible":false},{"text":"Actin","correct":false,"visible":false},{"text":"Myosin","correct":false,"visible":false},{"text":"Tropomyosin","correct":false,"visible":false},{"text":"Troponin","correct":false,"visible":false}]},{"id":5626,"text":"Lumbricals originate from which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 801.","responses":[{"text":"Flexor carpi ulnaris","correct":false,"visible":false},{"text":"Palmaris longus","correct":false,"visible":false},{"text":"Flexor digitorum profundus","correct":true,"visible":false},{"text":"Flexor carpi radialis","correct":false,"visible":false},{"text":"Flexor digitorum superficialis","correct":false,"visible":false}]},{"id":5627,"text":"The terminal cisternae, lying next to the T-tubules in a sarcomere of skeletal muscle, is a part of which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 97.","responses":[{"text":"Lysosome","correct":false,"visible":false},{"text":"Golgi apparatus","correct":false,"visible":false},{"text":"Sarcoplasmic reticulum","correct":true,"visible":false},{"text":"Rough endoplasmic reticulum","correct":false,"visible":false},{"text":"Smooth endoplasmic reticulum","correct":false,"visible":false}]},{"id":5633,"text":"What is the portion of myofibril between two consecutive Z-lines called?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79.","responses":[{"text":"A band","correct":false,"visible":false},{"text":"Sarcomere","correct":true,"visible":false},{"text":"I band","correct":false,"visible":false},{"text":"H zone","correct":false,"visible":false},{"text":"M line","correct":false,"visible":false}]},{"id":5637,"text":"The femoral artery is the continuation of which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 713.","responses":[{"text":"Internal iliac artery at the level of the inguinal ligament","correct":false,"visible":false},{"text":"External iliac artery above the inguinal ligament","correct":false,"visible":false},{"text":"None of these","correct":true,"visible":false},{"text":"Internal iliac artery above the inguinal ligament","correct":false,"visible":false},{"text":"External iliac artery at the level of the inguinal ligament","correct":false,"visible":false}]},{"id":5638,"text":"The triceps brachii muscle has three heads. Which of the following is the origin of the lateral head of triceps brachii?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 744, 745.","responses":[{"text":"Lower half of the anterior surface of humeral shaft","correct":false,"visible":false},{"text":"Upper half of the anterior surface of humeral shaft","correct":false,"visible":false},{"text":"Lower half of the posterior surface of humeral shaft","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Upper half of the posterior surface of humeral shaft","correct":true,"visible":false}]},{"id":5639,"text":"Myofibrils are formed from which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79.","responses":[{"text":"Sarcomeres","correct":false,"visible":false},{"text":"Myosin","correct":false,"visible":false},{"text":"Actin","correct":false,"visible":false},{"text":"Myosin and actin filaments","correct":true,"visible":false},{"text":"Sarcolemma","correct":false,"visible":false}]},{"id":5640,"text":"A 60-year-old man presents to the outpatient department with a loss of sensation in the anterolateral aspect of the thigh due to damage to the lateral cutaneous nerve. The lateral cutaneous nerve is a branch of which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 558.","responses":[{"text":"Sacral plexus","correct":false,"visible":false},{"text":"Lumbar plexus","correct":true,"visible":false},{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Obturator nerve","correct":false,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false}]},{"id":5642,"text":"Which of the following muscles is likely to be paralyzed if the suprascapular notch gets calcified?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 706, 707.","responses":[{"text":"Deltoid","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Subscapularis","correct":false,"visible":false},{"text":"Infraspinatus","correct":true,"visible":false},{"text":"Pectolaris major","correct":false,"visible":false}]},{"id":5643,"text":"Which of the following is correct about Paget's disease of bone?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1183.","responses":[{"text":"Histologically bone shows a characteristic mosaic pattern","correct":true,"visible":false},{"text":"Children are most commonly affected","correct":false,"visible":false},{"text":"Another name for it is osteoporosis","correct":false,"visible":false},{"text":"It is due to vitamin D deficiency","correct":false,"visible":false},{"text":"It is more common in Pakistan than in America","correct":false,"visible":false}]},{"id":5771,"text":"Which of the following muscles are innervated by both obturator and sciatic nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 708.","responses":[{"text":"Semitendinosus","correct":false,"visible":false},{"text":"Adductor magnus","correct":true,"visible":false},{"text":"Pectineus","correct":false,"visible":false},{"text":"Adductor longus","correct":false,"visible":false},{"text":"Biceps femoris","correct":false,"visible":false}]},{"id":5809,"text":"Which nerve is subject to injury in a fracture of the midshaft of the humerus?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 213.","responses":[{"text":"Median nerve","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Musculocutaneous nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":true,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false}]},{"id":5901,"text":"Which of the following structures passes superficial to the flexor retinaculum?","explanation":null,"reference":"Halliday NL, Chung HM. BRS: Gross Anatomy. 9th ed. Wolters Kluwer; 2019: 306.","responses":[{"text":"Flexor carpi longus","correct":false,"visible":false},{"text":"Flexor carpi ulnaris","correct":false,"visible":false},{"text":"Flexor digitorum superficialis","correct":false,"visible":false},{"text":"Flexor carpi radialis","correct":false,"visible":false},{"text":"Ulnar artery","correct":true,"visible":false}]},{"id":5935,"text":"Which of the following muscles is/are found in the trochanteric fossa?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 723.","responses":[{"text":"Obturator externus, superior gemellus, and inferior gemellus","correct":false,"visible":false},{"text":"Obturator externus","correct":false,"visible":false},{"text":"Obturator internus, superior gemellus, and inferior gemellus","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Obturator internus","correct":false,"visible":false}]},{"id":5938,"text":"Which of the following muscles is a powerful adductor and medial rotator of the arm?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 167.","responses":[{"text":"Pectoralis minor","correct":false,"visible":false},{"text":"Teres minor","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Subscapularis","correct":false,"visible":false},{"text":"Pectoralis major","correct":true,"visible":false}]},{"id":5941,"text":"Which of the following muscles holds fractured clavicle in order to prevent damage to the subclavian vein?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 169.","responses":[{"text":"Sternocleidomastoid","correct":false,"visible":false},{"text":"Subclavius","correct":true,"visible":false},{"text":"Deltoid","correct":false,"visible":false},{"text":"Trapezius","correct":false,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false}]},{"id":5997,"text":"The lateral circumflex femoris artery is a direct branch of which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 714.","responses":[{"text":"Profunda femoris artery","correct":true,"visible":false},{"text":"Popliteal artery","correct":false,"visible":false},{"text":"Obturator artery","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Femoral artery","correct":false,"visible":false}]},{"id":5998,"text":"Which of the following is correct about the inferior gluteal nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 733.","responses":[{"text":"It passes anterior to piriformis","correct":false,"visible":false},{"text":"It passes inferior to piriformis","correct":true,"visible":false},{"text":"It pierces through deep fascia","correct":false,"visible":false},{"text":"It gives off cutaneous branches","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":5999,"text":"A patient is suffering from pain and swelling at the knee joint. He is given aspirin. What is the mechanism of action of aspirin?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 499.","responses":[{"text":"Inhibition of platelet formation","correct":false,"visible":false},{"text":"Inhibition of lipoxygenase","correct":false,"visible":false},{"text":"Inhibition of leukocytes","correct":false,"visible":false},{"text":"Inhibition of erythrocyte formation","correct":false,"visible":false},{"text":"Inhibition of cyclooxygenase","correct":true,"visible":false}]},{"id":6000,"text":"A 24-year-old man is brought into the emergency room after he has met a motorbike accident. X-ray shows fracture of shaft of humerus distal to the deltoid tuberosity. Which of the following nerve is likely to be damaged?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 146, 155.","responses":[{"text":"Posterior interosseous nerve","correct":false,"visible":false},{"text":"Axillary nerve","correct":false,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Radial nerve","correct":true,"visible":false},{"text":"Median nerve","correct":false,"visible":false}]},{"id":6001,"text":"The parathyroid hormone plays a critical role in calcium homeostasis. Which of the following is seen as the body attempts to maintain the serum calcium levels within the normal range?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1001.","responses":[{"text":"Decline in parathyroid hormone levels","correct":false,"visible":false},{"text":"Inhibition of vitamin D synthesis","correct":false,"visible":false},{"text":"Excretion of calcium from kidneys","correct":false,"visible":false},{"text":"Hypertrophy of chondrocytes","correct":false,"visible":false},{"text":"Softening of bones","correct":true,"visible":false}]},{"id":6002,"text":"Which of the following ions are required for the exocytosis of neurotransmitters at the neuromuscular junction?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 93.","responses":[{"text":"K+ ions","correct":false,"visible":false},{"text":"Na+ ions","correct":false,"visible":false},{"text":"HCO3- ions","correct":false,"visible":false},{"text":"Cl- ions","correct":false,"visible":false},{"text":"Ca+2 ions","correct":true,"visible":false}]},{"id":6003,"text":"In a patient, the iliopsoas is found paralyzed. Which of the following muscle will undergo hypertrophy to compensate for hip flexion?","explanation":"In a patient with **paralyzed iliopsoas**, the **tensor fascia latae** would likely undergo hypertrophy to compensate for hip flexion. This muscle assists in flexing the hip and would take on a greater role if the iliopsoas is compromised.\r\n\r\n---\r\n\r\nVastus intermedius is part of the quadriceps group and is primarily involved in knee extension, not hip flexion.\r\n\r\nThe pectineus does assist in hip flexion, but it is not the primary compensatory muscle for the iliopsoas.\r\n\r\nThe semimembranosus is one of the hamstring muscles and is more involved in knee flexion and hip extension, not hip flexion.\r\n\r\nThe rectus femoris is part of the quadriceps group and does assist in hip flexion, but it is not the primary muscle that would undergo hypertrophy.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 725.","responses":[{"text":"Vastus intermedius","correct":false,"visible":false},{"text":"Rectus femoris","correct":false,"visible":false},{"text":"Pectineus","correct":false,"visible":false},{"text":"Semimembranosus","correct":false,"visible":false},{"text":"Tensor fascia latae","correct":true,"visible":false}]},{"id":6004,"text":"In a child suffering from influenza and chickenpox, aspirin is contraindicated because of the risk of which of the following?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1123.","responses":[{"text":"Reye's syndrome","correct":true,"visible":false},{"text":"Rickets","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Paget's disease","correct":false,"visible":false},{"text":"Osteopetrosis","correct":false,"visible":false}]},{"id":6005,"text":"Which of the following is present in the extracellular matrix of cartilage?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 131.","responses":[{"text":"Tropomyosin","correct":false,"visible":false},{"text":"Troponin","correct":false,"visible":false},{"text":"Aggrecan","correct":true,"visible":false},{"text":"Titin","correct":false,"visible":false},{"text":"Myosin","correct":false,"visible":false}]},{"id":6006,"text":"Which of the following branch is the major blood supply to the femoral head and neck?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 791.","responses":[{"text":"Obturator artery","correct":false,"visible":false},{"text":"Lateral circumflex femoral artery","correct":false,"visible":false},{"text":"Superior gluteal artery","correct":false,"visible":false},{"text":"Inferior gluteal artery","correct":false,"visible":false},{"text":"Medial circumflex femoral artery","correct":true,"visible":false}]},{"id":6007,"text":"Which of the following bones is present in the proximal row of carpals?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 149.","responses":[{"text":"Trapezium","correct":false,"visible":false},{"text":"Trapezoid","correct":false,"visible":false},{"text":"Hamate","correct":false,"visible":false},{"text":"Capitate","correct":false,"visible":false},{"text":"Lunate","correct":true,"visible":false}]},{"id":6008,"text":"Which of the following is not a component of the adductor canal?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 715.","responses":[{"text":"Femoral vein","correct":false,"visible":false},{"text":"Saphenous nerve","correct":false,"visible":false},{"text":"Nerve to vastus medialis","correct":false,"visible":false},{"text":"Femoral artery","correct":false,"visible":false},{"text":"Great saphenous vein","correct":true,"visible":false}]},{"id":6009,"text":"Fracture of the neck of the femur causes avascular necrosis of the femoral head. Lack of supply from which of the following artery is the reason behind this?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 791.","responses":[{"text":"Inferior gluteal artery","correct":false,"visible":false},{"text":"Superior gluteal artery","correct":false,"visible":false},{"text":"Inferior circumflex femoral artery","correct":false,"visible":false},{"text":"Medial circumflex femoral artery","correct":true,"visible":false},{"text":"Obturator artery","correct":false,"visible":false}]},{"id":6010,"text":"Which of the following is correct about fibrocartilage?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 134.","responses":[{"text":"It is abundant in proteoglycans","correct":false,"visible":false},{"text":"Nasal cartilage is of fibrocartilaginous variety","correct":false,"visible":false},{"text":"It is composed of type 2 collagen only","correct":false,"visible":false},{"text":"Regions surrounding lacunae are relatively free of fibers","correct":true,"visible":false},{"text":"It is covered by perichondrium","correct":false,"visible":false}]},{"id":6011,"text":"The joint between radius and ulna is classified as which type of joint?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 274, 276.","responses":[{"text":"Gomphosis","correct":false,"visible":false},{"text":"Synovial","correct":true,"visible":false},{"text":"Suture","correct":false,"visible":false},{"text":"Fibrous","correct":false,"visible":false},{"text":"Symphysis","correct":false,"visible":false}]},{"id":6012,"text":"Flexor carpi ulnaris is innervated by which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 193.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Posterior interosseus branch of median nerve","correct":false,"visible":false},{"text":"Ulnar nerve","correct":true,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Median nerve","correct":false,"visible":false}]},{"id":6013,"text":"Dupuytren's contracture is due to which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 258.","responses":[{"text":"Median nerve damage","correct":false,"visible":false},{"text":"Thickening of palmar aponeurosis of ulnar side","correct":true,"visible":false},{"text":"Rupture of flexor retinaculum","correct":false,"visible":false},{"text":"Rupture of extensor retinaculum","correct":false,"visible":false},{"text":"Radial nerve damage","correct":false,"visible":false}]},{"id":6015,"text":"Scapular anastomosis is formed between which part of the subclavian and axillary artery?","explanation":null,"reference":"(1) Halliday NL, M C Harold, Won C Kyung. BRS: Gross Anatomy. 10th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2020: 315.\r\n\r\n(2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 723.","responses":[{"text":"4th part of subclavian and 1st part of axillary","correct":false,"visible":false},{"text":"1st part of subclavian and 3rd part of axillary","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"3rd part of subclavian and 1st part of axillary","correct":false,"visible":false},{"text":"2nd part of subclavian and 3rd part of axillary","correct":false,"visible":false}]},{"id":6016,"text":"Which of the following arteries is not involved in the formation of scapular anastomosis?","explanation":null,"reference":"Halliday NL, M C Harold, Won C Kyung. BRS: Gross Anatomy. 10th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2020: 315.","responses":[{"text":"Circumflex humeral","correct":false,"visible":false},{"text":"Thyrocervical","correct":false,"visible":false},{"text":"Lateral thoracic","correct":true,"visible":false},{"text":"Suprascapular","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":6017,"text":"Scapular anastomosis opens up when which of the following arteries is blocked?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 185, 196.","responses":[{"text":"Proximal part of radial artery","correct":false,"visible":false},{"text":"Brachial artery","correct":false,"visible":false},{"text":"Ulnar artery","correct":false,"visible":false},{"text":"Proximal part of axillary artery","correct":true,"visible":false},{"text":"Proximal part of subclavian artery","correct":false,"visible":false}]},{"id":6018,"text":"Which of the following muscles is present anterior to the adductor canal?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 715.","responses":[{"text":"Sartorius","correct":true,"visible":false},{"text":"Adductor longus","correct":false,"visible":false},{"text":"Rectus femoris","correct":false,"visible":false},{"text":"Gracilis","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":6019,"text":"Which of the following muscles is present posterior to the adductor canal?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 715.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Sartorius","correct":false,"visible":false},{"text":"Gracilis","correct":false,"visible":false},{"text":"Rectus femoris","correct":false,"visible":false},{"text":"Adductor longus","correct":true,"visible":false}]},{"id":6020,"text":"The adductor canal is located in which region of the thigh?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 715.","responses":[{"text":"Middle third of thigh","correct":true,"visible":false},{"text":"Posterior thigh","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Upper third of thigh","correct":false,"visible":false},{"text":"Lower third of thigh","correct":false,"visible":false}]},{"id":6021,"text":"The axillary artery is a continuation of which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 185.","responses":[{"text":"Thoracic artery","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Femoral artery","correct":false,"visible":false},{"text":"Subclavian artery","correct":true,"visible":false},{"text":"Thyrocervical artery","correct":false,"visible":false}]},{"id":6022,"text":"Which of the following parts of the axillary artery is oriented distal to the pectoralis minor muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 185.","responses":[{"text":"3rd part of axillary artery","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"1st part of axillary artery","correct":false,"visible":false},{"text":"4th part of axillary artery","correct":false,"visible":false},{"text":"2nd part of axillary artery","correct":false,"visible":false}]},{"id":6023,"text":"Which of the following is not a branch of the axillary artery?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 185, 187.","responses":[{"text":"Thyrocervical artery","correct":true,"visible":false},{"text":"Posterior circumflex humeral artery","correct":false,"visible":false},{"text":"Thoraco-acromial artery","correct":false,"visible":false},{"text":"Subscapular artery","correct":false,"visible":false},{"text":"Anterior circumflex humeral artery","correct":false,"visible":false}]},{"id":6024,"text":"Which of the following arteries arises from the third part of the axillary artery?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 185.","responses":[{"text":"Subscapular artery","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Radial artery","correct":false,"visible":false},{"text":"Ulnar artery","correct":false,"visible":false},{"text":"Brachial artery","correct":false,"visible":false}]},{"id":6025,"text":"The movement of the little finger is impaired due to the fracture of the elbow. It is due to the rupture of which of the following?","explanation":null,"reference":"Davis DD, Kane SM. Ulnar nerve entrapment. In: StatPearls. StatPearls Publishing; 2022. Accessed September 15, 2022. http://www.ncbi.nlm.nih.gov/books/NBK555929/","responses":[{"text":"Medial collateral ligament","correct":true,"visible":false},{"text":"Lateral collateral ligament","correct":false,"visible":false},{"text":"Bicipital aponeurosis","correct":false,"visible":false},{"text":"Tendon of flexor carpi ulnaris","correct":false,"visible":false},{"text":"Tendon of flexor carpi radialis","correct":false,"visible":false}]},{"id":6026,"text":"Which of the following statements is correct about the development of skeletal system?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 341, 363, 367, 377.","responses":[{"text":"Fingers and toes formation occur due to death of apical ectodermal ridge cells by apoptosis","correct":true,"visible":false},{"text":"Upper limbs develop two days after lower limbs","correct":false,"visible":false},{"text":"Limb development starts in second week of development","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Joints development starts in fourth week of development","correct":false,"visible":false}]},{"id":6030,"text":"Where does the subclavius insert on the clavicle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 713.","responses":[{"text":"Anterior surface of lateral 2/3rd of clavicle","correct":false,"visible":false},{"text":"Inferior surface of lateral 2/3rd of clavicle","correct":false,"visible":false},{"text":"Posterior surface of lateral 2/3rd of clavicle","correct":false,"visible":false},{"text":"Inferior surface of medial 1/3rd of clavicle","correct":true,"visible":false},{"text":"Sternal head","correct":false,"visible":false}]},{"id":6031,"text":"Nerve conduction velocity increases with which of the following?","explanation":null,"reference":"Costanzo LS. Physiology. 6th ed. Elsevier; 2018: 25, 26.","responses":[{"text":"Decrease in diameter of axon","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Decrease in thickness of myelin sheath","correct":false,"visible":false},{"text":"Demyelination of axon","correct":false,"visible":false},{"text":"Increase in diameter of axon","correct":true,"visible":false}]},{"id":6032,"text":"Transverse midshaft fracture of radius and ulna is treated by which of the following?","explanation":null,"reference":"Dow Lecture slides: Locomotor module, Subject: Orthopaedics, Topic: Management of Fractures \u0026 Dislocations of the Upper Limb, Sub-topic: Monteggia Fractures.","responses":[{"text":"All of these","correct":false,"visible":false},{"text":"Open reduction and plate","correct":true,"visible":false},{"text":"Close reduction and slab","correct":false,"visible":false},{"text":"Open reduction and nail","correct":false,"visible":false},{"text":"Close reduction and plaster cast","correct":false,"visible":false}]},{"id":6033,"text":"A boy was unable to raise his arm above the shoulder level due to damage to a nerve. This nerve supplies which of the following muscles?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 179, 180.","responses":[{"text":"Pectoralis major","correct":false,"visible":false},{"text":"Serratus anterior","correct":true,"visible":false},{"text":"Deltoid","correct":false,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false},{"text":"Infraspinatus","correct":false,"visible":false}]},{"id":6034,"text":"Which muscle flexes the leg better when the thigh is also flexed?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 728, 729.","responses":[{"text":"Short head of biceps femoris","correct":false,"visible":false},{"text":"Semitendinosus","correct":false,"visible":false},{"text":"Adductor longus","correct":false,"visible":false},{"text":"Long head of biceps femoris","correct":true,"visible":false},{"text":"Semimembranosus","correct":false,"visible":false}]},{"id":6036,"text":"Which of the following is correct about the route of the great saphenous vein?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 564.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Posterior to medial malleolus","correct":false,"visible":false},{"text":"Posterior to medial epicondyle of femur and tibia","correct":false,"visible":false},{"text":"Anterior to medial epicondyle of femur and tibia","correct":false,"visible":false},{"text":"Superficial to fascia lata","correct":true,"visible":false}]},{"id":6037,"text":"In the 18th to 20th century, the decline in mortality level occurred due to which of the following?","explanation":null,"reference":null,"responses":[{"text":"Diseases","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Prevention","correct":true,"visible":false},{"text":"Carelessness","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":6038,"text":"Limping is seen in patients with an impaired function of which of the following muscles?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 740.","responses":[{"text":"Gluteus medius","correct":true,"visible":false},{"text":"Gluteus maximus","correct":false,"visible":false},{"text":"Semitendinosus","correct":false,"visible":false},{"text":"Semimembranosus","correct":false,"visible":false},{"text":"Rectus abdominis","correct":false,"visible":false}]},{"id":6039,"text":"Serum levels of which of the following help in the regulation of calcium and phosphorus levels in the blood?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 386.","responses":[{"text":"Vitamin D","correct":true,"visible":false},{"text":"Vitamin B","correct":false,"visible":false},{"text":"Glycogen","correct":false,"visible":false},{"text":"Vitamin C","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false}]},{"id":6040,"text":"If the potential of a disorder increases, it may result in which of the following?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Injury.","responses":[{"text":"Disability","correct":true,"visible":false},{"text":"Impairment","correct":false,"visible":false},{"text":"Injury","correct":false,"visible":false},{"text":"Functionality","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":6041,"text":"Where does cartilage originate from?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 52.","responses":[{"text":"Epithelium","correct":false,"visible":false},{"text":"Mesoderm","correct":true,"visible":false},{"text":"Ectoderm","correct":false,"visible":false},{"text":"Proctoderm","correct":false,"visible":false},{"text":"Endoderm","correct":false,"visible":false}]},{"id":6065,"text":"Which of the following terms refers to decreased bone mass?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1179.","responses":[{"text":"Osteomalacia","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Paget's disease","correct":false,"visible":false},{"text":"Osteopenia","correct":true,"visible":false}]},{"id":6086,"text":"Which one of the following can the venom of the sea snake be categorized as?","explanation":null,"reference":"Dow Lecture Slides. Locomotor module, Subject: Community Medicine, Topic, Snake Bite, and its Preventive Measures, Sub-topic: Venom and its Classification.","responses":[{"text":"Neurotoxic","correct":false,"visible":false},{"text":"Vasculotoxic","correct":false,"visible":false},{"text":"Hepatotoxic","correct":false,"visible":false},{"text":"Myotoxic","correct":true,"visible":false},{"text":"Nephrotoxic","correct":false,"visible":false}]},{"id":6087,"text":"Tendon of which of the following muscles passes through lesser sciatic foramen?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 555.","responses":[{"text":"Piriformis","correct":false,"visible":false},{"text":"Quadratus femoris","correct":false,"visible":false},{"text":"Obturator externus","correct":false,"visible":false},{"text":"Gluteus medius","correct":false,"visible":false},{"text":"Obturator internus","correct":true,"visible":false}]},{"id":6088,"text":"An avalanche is an event that occurs when a cohesive slab of snow lying upon a weaker layer of snow fractures and slides down a steep slope. Which type of disaster is 'avalanche'?","explanation":null,"reference":"Dow Lecture Slides, Locomotor Module, Subject: Community Medicine, Topic: Disaster Management, Sub-topic: Types of Disaster","responses":[{"text":"Acts of terrorism","correct":false,"visible":false},{"text":"Meteorological","correct":false,"visible":false},{"text":"Tectonic","correct":false,"visible":false},{"text":"Structure failures","correct":false,"visible":false},{"text":"Topographical","correct":true,"visible":false}]},{"id":6089,"text":"A patient has suffered a fracture of the surgical neck of the humerus. Which nerve is most closely related to this structure?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 155.","responses":[{"text":"Median nerve","correct":false,"visible":false},{"text":"Axillary nerve","correct":true,"visible":false},{"text":"Circumflex scapular vessels","correct":false,"visible":false},{"text":"Radial nerve","correct":false,"visible":false},{"text":"Profunda brachii","correct":false,"visible":false}]},{"id":6090,"text":"A 55-year-old man presents to the outpatient department with the history of falling on his outstretched hand with flexed elbow. The medial epicondyle is avulsed. Which of the following muscle does not take origin from the fractured region?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 218, 219.","responses":[{"text":"Flexor carpi radialis","correct":false,"visible":false},{"text":"Flexor digitorum profundus","correct":true,"visible":false},{"text":"Palmaris longus","correct":false,"visible":false},{"text":"Flexor carpi ulnaris","correct":false,"visible":false},{"text":"Flexor digitorum superficialis","correct":false,"visible":false}]},{"id":6091,"text":"A 43-year-old man presents to the outpatient department with a complaint of pain in his tibia bone for the past two years. Upon investigation, he opens up about his history of extra-marital affairs. A Magnetic Resonance Imaging (MRI) report reveals the development of gumma as well. Which microorganism could he be suspected to be infected by?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1186, 1187.\r\n\r\n(2) Tsuboi M, Nishijima T, Teruya K, Kikuchi Y, Gatanaga H, Oka S. Cerebral syphilitic gumma within 5 months of syphilis in hiv-infected patient. Emerging Infectious Diseases. Published October 2016. Accessed September 18, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5038426/","responses":[{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Treponema pallidum","correct":true,"visible":false},{"text":"Mycobacterium tuberculosis","correct":false,"visible":false},{"text":"Streptococcus pyogenes","correct":false,"visible":false},{"text":"Neisseria gonorrhoeae","correct":false,"visible":false}]},{"id":6092,"text":"A 20-year-old man falls from the parallel bar during the Olympic trial. A neurologic examination reveals that he has a lesion of the lateral cord of the brachial plexus. Which of the following muscles is most likely to be weakened by this injury?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 193.","responses":[{"text":"Pectoralis major","correct":true,"visible":false},{"text":"Deltoid","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Latissimus dorsi","correct":false,"visible":false},{"text":"Subscapularis","correct":false,"visible":false}]},{"id":6093,"text":"A young woman is unable to climb up the stairs. Which of the following muscles is most likely to be affected in this case?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 725.","responses":[{"text":"Obturator internus","correct":false,"visible":false},{"text":"Gluteus minimus","correct":false,"visible":false},{"text":"Gluteus maximus","correct":true,"visible":false},{"text":"Obturator externus","correct":false,"visible":false},{"text":"Biceps femoris","correct":false,"visible":false}]},{"id":6094,"text":"Which of the following is the principal protein present in bones?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 143.","responses":[{"text":"Collagen type I","correct":true,"visible":false},{"text":"Collagen type IV","correct":false,"visible":false},{"text":"Fibronectin","correct":false,"visible":false},{"text":"Collagen type III","correct":false,"visible":false},{"text":"Elastin","correct":false,"visible":false}]},{"id":6095,"text":"Which of the following organisms can get a person osteomyelitis if they already have genitourinary tract infection?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1185, 1186.","responses":[{"text":"E. coli","correct":true,"visible":false},{"text":"Streptococci","correct":false,"visible":false},{"text":"Salmonella","correct":false,"visible":false},{"text":"Staphylococci","correct":false,"visible":false},{"text":"Moraxella","correct":false,"visible":false}]},{"id":6096,"text":"A person is trying to extend his thumb but finds himself unable to do so. Which of the following nerves must be damaged?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 208, 213.","responses":[{"text":"Axillary nerve","correct":false,"visible":false},{"text":"Radial nerve passing between superficial and deep muscles","correct":true,"visible":false},{"text":"Median nerve","correct":false,"visible":false},{"text":"Ulnar nerve","correct":false,"visible":false},{"text":"Radial nerve passing superficial to extensor retinaculum","correct":false,"visible":false}]},{"id":6097,"text":"Which of the following muscles originate from 3rd to 5th ribs?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 168.","responses":[{"text":"Serratus anterior","correct":false,"visible":false},{"text":"Deltoid","correct":false,"visible":false},{"text":"Teres minor","correct":false,"visible":false},{"text":"Pectoralis major","correct":false,"visible":false},{"text":"Pectoralis minor","correct":true,"visible":false}]},{"id":6151,"text":"Which of the following is true regarding generation of an action potential?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 67.","responses":[{"text":"The polarity of a cell increases","correct":false,"visible":false},{"text":"Negative ions move from extracellular to intracellular compartment","correct":false,"visible":false},{"text":"Positive ions move from the extracellular to intracellular compartment","correct":true,"visible":false},{"text":"Inside of the cell is more negative than the outside","correct":false,"visible":false},{"text":"Potassium channels open throughout the membrane","correct":false,"visible":false}]},{"id":6154,"text":"Which of the following is not a part of the roof of a cubital fossa?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 209.","responses":[{"text":"Skin","correct":false,"visible":false},{"text":"Median nerve","correct":true,"visible":false},{"text":"Bicipital aponeurosis","correct":false,"visible":false},{"text":"Fascia","correct":false,"visible":false},{"text":"Subcutaneous tissue","correct":false,"visible":false}]},{"id":6172,"text":"On the gluteal surface of the ilium, where is the origin of the gluteus medius muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 723.","responses":[{"text":"Anterior gluteal line","correct":false,"visible":false},{"text":"Posterior gluteal line","correct":false,"visible":false},{"text":"Inferior gluteal line","correct":false,"visible":false},{"text":"Between posterior and superior gluteal line","correct":false,"visible":false},{"text":"Between anterior and posterior gluteal line","correct":true,"visible":false}]},{"id":6173,"text":"When the membrane is only permeable to K+ ions, the ratio of K+ inside to outside the cell is 35:1. What is the Nernst potential across the cell membrane in this case?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 67.","responses":[{"text":"-85 mV","correct":false,"visible":false},{"text":"-70 mV","correct":false,"visible":false},{"text":"-94 mV","correct":true,"visible":false},{"text":"-90 mV","correct":false,"visible":false},{"text":"-61 mV","correct":false,"visible":false}]},{"id":6174,"text":"A 36-year-old woman with a lump in the breast was diagnosed with breast cancer and underwent a mastectomy and surgical removal of axillary lymph nodes. After the surgery, she was unable to use one of her upper limbs, of the same side of the surgery, to climb. Which of the following nerves was damaged?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 180.","responses":[{"text":"DorsaI scapular nerve","correct":false,"visible":false},{"text":"Subscapular nerve","correct":false,"visible":false},{"text":"Thoracodorsal nerve","correct":true,"visible":false},{"text":"Long thoracic nerve","correct":false,"visible":false},{"text":"SuprascapuIar nerve","correct":false,"visible":false}]},{"id":6177,"text":"Which of the following is not supplied by the obturator nerve?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 586.","responses":[{"text":"Hamstring part of adductor magnus","correct":true,"visible":false},{"text":"Adductor brevis","correct":false,"visible":false},{"text":"GraciIis","correct":false,"visible":false},{"text":"Adductor longus","correct":false,"visible":false},{"text":"Obturator externus","correct":false,"visible":false}]},{"id":6179,"text":"Which of the following passes through the adductor canal?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 715.","responses":[{"text":"Nerve to the vastus lateralis","correct":false,"visible":false},{"text":"Great saphenous vein","correct":false,"visible":false},{"text":"Small saphenous vein","correct":false,"visible":false},{"text":"Popliteal artery","correct":false,"visible":false},{"text":"Femoral vein","correct":true,"visible":false}]},{"id":6183,"text":"What is the mechanism of action of acetaminophen?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 307.","responses":[{"text":"InhIblts COX-1","correct":false,"visible":false},{"text":"Inhibits COX-2","correct":false,"visible":false},{"text":"Inhibits COX-1 and COX-3","correct":false,"visible":false},{"text":"Inhibits COX-1, COX-2, and COX-3","correct":true,"visible":false},{"text":"InhIblts COX-3","correct":false,"visible":false}]},{"id":6193,"text":"What is the mechanism of action of methylxanthine?","explanation":"**Methylxanthines**, such as theophylline, is the **inhibition of phosphodiesterase**. By inhibiting this enzyme, methylxanthines increase the levels of cyclic AMP (cAMP), leading to bronchodilation and other effects.\r\n\r\n---\r\n\r\nBeta-adrenergic receptor stimulation: This is the mechanism of action for drugs like albuterol, not methylxanthines.\r\nRegulation of intracellular fluoride levels: There is no known pharmacological mechanism involving the regulation of intracellular fluoride levels by methylxanthines.\r\nAlpha-adrenergic receptor stimulation: This mechanism is not associated with methylxanthines; it is more commonly seen with drugs like phenylephrine.","reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 194.","responses":[{"text":"Alpha-adrenergic receptor stimulation","correct":false,"visible":false},{"text":"Regulation of intracellular sodium levels","correct":false,"visible":false},{"text":"Beta-adrenergic receptor stimulation","correct":false,"visible":false},{"text":"Regulation of intracellular fluoride levels","correct":false,"visible":false},{"text":"Inhibition of phosphodiesterase","correct":true,"visible":false}]},{"id":6195,"text":"A 5-year-old presents with symptoms of viral infection. Due to the risk of which of the following would aspirin not be prescribed to him?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 123.","responses":[{"text":"Chediak-Higashi syndrome","correct":false,"visible":false},{"text":"Thorn's syndrome","correct":false,"visible":false},{"text":"Bantis syndrome","correct":false,"visible":false},{"text":"Barlow syndrome","correct":false,"visible":false},{"text":"Reye's syndrome","correct":true,"visible":false}]},{"id":6206,"text":"Which of the following is incorrect regarding the joints in the hand?","explanation":null,"reference":"Ladd AL, Weiss APC, Crisco JJ, et al. The thumb carpometacarpal joint: anatomy, hormones, and biomechanics. Instr Course Lect. 2013;62:165-179. Accessed September 16, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3935621/","responses":[{"text":"The interphalangeal joints are hinge joints","correct":false,"visible":false},{"text":"There is restricted movement at the intercarpal joints","correct":false,"visible":false},{"text":"The metacarpophalangeal joints are synovial condyloid joints","correct":false,"visible":false},{"text":"At the metacarpophalangeal joint, the base of the phalanx articulates with the the head of the metacarpal","correct":false,"visible":false},{"text":"No movement occurs at metacarpocarpal joint of the thumb","correct":true,"visible":false}]},{"id":6208,"text":"Which of the following modalities should be used for upper limb soft tissues?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Radiology, Topic: Introduction to Medical Imaging, Sub-topic: Uses of MRI.","responses":[{"text":"X-ray","correct":false,"visible":false},{"text":"Computerized tomography (CT)","correct":false,"visible":false},{"text":"Magnetic resonance imaging (MRI)","correct":true,"visible":false},{"text":"Fluoroscopy","correct":false,"visible":false},{"text":"Nuclear imaging","correct":false,"visible":false}]},{"id":6213,"text":"Which of the following is one of the key principles of health education?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Health Promotion and Health Education, Subtopic: Stages of Health Education.","responses":[{"text":"Awareness","correct":false,"visible":false},{"text":"Promotion","correct":false,"visible":false},{"text":"Trial","correct":false,"visible":false},{"text":"Motivation","correct":true,"visible":false},{"text":"Advocacy","correct":false,"visible":false}]},{"id":6215,"text":"At the knee joint, the patellar ligament and oblique popliteal ligament respectively correspond to which of the following pairs?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 706, 731.","responses":[{"text":"GraciIis and biceps","correct":false,"visible":false},{"text":"Quadriceps and semitendinosus","correct":false,"visible":false},{"text":"Biceps and semitendinosus","correct":false,"visible":false},{"text":"Quadriceps and gracilis","correct":false,"visible":false},{"text":"Quadriceps and semimembranosus","correct":true,"visible":false}]},{"id":6216,"text":"Which of the following structures is intracapsular at the knee joint?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 795.","responses":[{"text":"Patellar ligament","correct":false,"visible":false},{"text":"Popliteus tendon","correct":true,"visible":false},{"text":"Tibial collateral ligament","correct":false,"visible":false},{"text":"Biceps femoris tendon","correct":false,"visible":false},{"text":"Oblique patellar ligament","correct":false,"visible":false}]},{"id":6223,"text":"Which of the following is correct regarding the developmental disorders of the skeletal system?","explanation":"bone","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1175, 1176, 1179.","responses":[{"text":"Osteopetrosis is characteristized by lesser bone mass","correct":false,"visible":false},{"text":"Thanatophoric dysplasia is harmless","correct":false,"visible":false},{"text":"Osteoporosis is marked by denser bone","correct":false,"visible":false},{"text":"Achondroplasia is the most common cause of dwarfism","correct":true,"visible":false},{"text":"Osteopetrosis is brittle bone disease","correct":false,"visible":false}]},{"id":6224,"text":"A 15-year-old boy is rushed to the emergency room after an automobile accident. He has weak knee extension, loss of function of quadriceps compartment, and loss of sensation over the anteromedial thigh and medial side of the calf. Which of the following nerves is most likely to be damaged?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 584, 596.","responses":[{"text":"Obturator nerve","correct":false,"visible":false},{"text":"Superior gluteal nerve","correct":false,"visible":false},{"text":"Femoral nerve","correct":true,"visible":false},{"text":"Sciatic nerve","correct":false,"visible":false},{"text":"Inferior gluteal nerve","correct":false,"visible":false}]},{"id":6225,"text":"A 12-year-old boy suffers an accident that injures the posterior triangle of his neck. He is unable to raise his hand to comb his hair. Which of the following muscles is most likely to be affected?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 179, 180.","responses":[{"text":"Levator scapulae","correct":false,"visible":false},{"text":"Latissimus dorsi","correct":false,"visible":false},{"text":"Teres major","correct":false,"visible":false},{"text":"Serratus anterior","correct":true,"visible":false},{"text":"Deltoid","correct":false,"visible":false}]},{"id":6226,"text":"Which part of the iliac crest is the attachment for the gluteus maximus muscle?","explanation":null,"reference":"(1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 723-724.\r\n\r\n(2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 567, 570-571.","responses":[{"text":"Lateral slope","correct":true,"visible":false},{"text":"Intermediate area","correct":false,"visible":false},{"text":"Internal lip","correct":false,"visible":false},{"text":"Medial slope","correct":false,"visible":false},{"text":"External lip","correct":false,"visible":false}]},{"id":6232,"text":"A 14-year-old boy was brought to the emergency room after he had slipped from a bike. He was observed to have restricted movement at his left knee while resistance in extension in right knee was also noticed. Which muscle might be involved in this?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 584.","responses":[{"text":"Flexors","correct":false,"visible":false},{"text":"Popliteus","correct":false,"visible":false},{"text":"Soleus","correct":false,"visible":false},{"text":"Hamstrings","correct":false,"visible":false},{"text":"Quadriceps","correct":true,"visible":false}]},{"id":6233,"text":"A patient was given an intramuscular injection. In which muscle is it commonly administered?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 181.","responses":[{"text":"Psoas minor","correct":false,"visible":false},{"text":"Intrinsic muscles","correct":false,"visible":false},{"text":"Psoas major","correct":false,"visible":false},{"text":"Deltoid","correct":true,"visible":false},{"text":"Extrinsic muscles","correct":false,"visible":false}]},{"id":6234,"text":"If the loss of motor function is observed in the anterior thigh and sensory function of the medial and anterior leg. Which of the following nerves is most likely suspected to be damaged?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 596.","responses":[{"text":"Radial","correct":false,"visible":false},{"text":"Popliteal","correct":false,"visible":false},{"text":"Femoral","correct":true,"visible":false},{"text":"Sciatic","correct":false,"visible":false},{"text":"Obturator","correct":false,"visible":false}]},{"id":6235,"text":"Which one of the following is not a principle of health education?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Health Promotion and Health Education.","responses":[{"text":"Knowing the customs","correct":false,"visible":false},{"text":"Trial","correct":true,"visible":false},{"text":"Good human relations","correct":false,"visible":false},{"text":"Learning by doing","correct":false,"visible":false},{"text":"Motivation","correct":false,"visible":false}]},{"id":6236,"text":"An X-ray shows an injury to the axillary nerve. Which muscle is most likely to be affected by this?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 180.","responses":[{"text":"Supraspinatus","correct":false,"visible":false},{"text":"Pectoralis major","correct":false,"visible":false},{"text":"Infraspinatus","correct":false,"visible":false},{"text":"Deltoid","correct":true,"visible":false},{"text":"Teres major","correct":false,"visible":false}]},{"id":6237,"text":"Which of the following muscles is not attached to either the lesser or greater tubercle of humerus?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 174.","responses":[{"text":"Subscapularis","correct":false,"visible":false},{"text":"Teres minor","correct":false,"visible":false},{"text":"Infraspinatus","correct":false,"visible":false},{"text":"Deltoid","correct":true,"visible":false},{"text":"Supraspinatus","correct":false,"visible":false}]},{"id":6239,"text":"As a result of road traffic accident, a person lost his supination. Which nerve is most likely to be damaged here?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 213, 221.","responses":[{"text":"Musculocutaneous","correct":false,"visible":false},{"text":"Brachial","correct":false,"visible":false},{"text":"Radial","correct":true,"visible":false},{"text":"Ulnar","correct":false,"visible":false},{"text":"Median","correct":false,"visible":false}]},{"id":6240,"text":"If all the vessels of the cruciate anastomosis are cut off, which artery will supply the femur?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 734.","responses":[{"text":"Superior gluteal artery","correct":true,"visible":false},{"text":"Inferior gluteal artery","correct":false,"visible":false},{"text":"Medial circumflex femoral artery","correct":false,"visible":false},{"text":"Lateral circumflex femoral artery","correct":false,"visible":false},{"text":"First perforating artery","correct":false,"visible":false}]},{"id":6241,"text":"Which of the following is an active form of vitamin D?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 998.","responses":[{"text":"1,25-dihydroxycholecalciferol","correct":true,"visible":false},{"text":"25-hydroxycholecalciferol","correct":false,"visible":false},{"text":"Riboflavin","correct":false,"visible":false},{"text":"Cholecalciferol","correct":false,"visible":false},{"text":"Niacin","correct":false,"visible":false}]},{"id":6243,"text":"Where is the triad present in skeletal muscle?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 201.","responses":[{"text":"I band","correct":false,"visible":false},{"text":"A-I junction","correct":true,"visible":false},{"text":"M band","correct":false,"visible":false},{"text":"A band","correct":false,"visible":false},{"text":"Z line","correct":false,"visible":false}]},{"id":6250,"text":"Which function is impaired by the fracture in the midshaft of ulna and radius?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 234.","responses":[{"text":"Wrist extension","correct":true,"visible":false},{"text":"Elbow flexion","correct":false,"visible":false},{"text":"Wrist flexion","correct":false,"visible":false},{"text":"Supination and pronation","correct":false,"visible":false},{"text":"Elbow extension","correct":false,"visible":false}]},{"id":6493,"text":"Which of the following is true about 'myosin filament'?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 79.","responses":[{"text":"It is present in A band","correct":true,"visible":false},{"text":"It contains titin","correct":false,"visible":false},{"text":"Isotropic to light","correct":false,"visible":false},{"text":"It is a structural protein","correct":false,"visible":false},{"text":"It is present in I band","correct":false,"visible":false}]},{"id":6494,"text":"Which of the following is the safest and easiest way of treating midshaft fracture of the humerus?","explanation":null,"reference":"Bounds EJ, Frane N, Kok SJ. Humeral shaft fractures. StatPearls. Published 2022. Accessed September 18, 2022. http://www.ncbi.nlm.nih.gov/books/NBK448074/","responses":[{"text":"Locking plate fixation","correct":false,"visible":false},{"text":"Pain relief medication only","correct":false,"visible":false},{"text":"Splint","correct":true,"visible":false},{"text":"Intramedullary nail","correct":false,"visible":false},{"text":"External fixation","correct":false,"visible":false}]},{"id":6495,"text":"'Geriatrics' is a branch of medicine that deals with which of the following?","explanation":null,"reference":"Dow Lecture Slides. Locomotor Module, Subject: Community Medicine, Topic: Elderly health, Sub-topic: Geriatrics.","responses":[{"text":"Cure and rehabilitation of the elderly","correct":false,"visible":false},{"text":"Prevention and rehabilitation of the elderly","correct":false,"visible":false},{"text":"Diagnosis of illness of the elderly","correct":false,"visible":false},{"text":"Management of the illness of the elderly","correct":false,"visible":false},{"text":"Prevention, cure and rehabilitation from the disease in the older adults","correct":true,"visible":false}]}
]

